import React from 'react';
import { Pressable, View } from 'react-native';
import { useTheme } from '../../theme/useTheme';
import { useControllableState } from '../../hooks/useControllableState';
import { Text } from '../Text/Text';
import { CheckIcon } from '../../icons';
import type { A11yProps } from '../../types';

export interface CheckboxProps extends A11yProps {
  /** Controlled checked value. */
  value?: boolean;
  /** Uncontrolled initial value. Default `false`. */
  defaultValue?: boolean;
  onValueChange?: (value: boolean) => void;
  /** Optional inline label rendered to the right. */
  label?: string;
  disabled?: boolean;
  testID?: string;
}

/**
 * A square checkbox with an optional label. Same controlled/uncontrolled API as
 * {@link Switch} and {@link Radio}.
 *
 * @remarks
 * Do: use for independent multi-select options. Use {@link Radio} for exclusive choice.
 * @example
 * <Checkbox label="Email me updates" value={on} onValueChange={setOn} />
 */
export function Checkbox({ value, defaultValue = false, onValueChange, label, disabled, accessibilityLabel, testID }: CheckboxProps) {
  const theme = useTheme();
  const [checked, setChecked] = useControllableState({ value, defaultValue, onChange: onValueChange });
  const c = theme.colors;

  return (
    <Pressable
      onPress={() => setChecked(!checked)}
      disabled={disabled}
      accessibilityRole="checkbox"
      accessibilityState={{ checked, disabled }}
      accessibilityLabel={accessibilityLabel ?? label}
      testID={testID}
      hitSlop={8}
      style={{ flexDirection: 'row', alignItems: 'center', gap: theme.space[3], opacity: disabled ? 0.5 : 1 }}
    >
      <View
        style={{
          width: 22, height: 22, borderRadius: 7, alignItems: 'center', justifyContent: 'center',
          backgroundColor: checked ? c.accent : 'transparent',
          borderWidth: checked ? 0 : 1.8,
          borderColor: c.borderStrong,
        }}
      >
        {checked && <CheckIcon size={14} color="#fff" />}
      </View>
      {label && <Text variant="body">{label}</Text>}
    </Pressable>
  );
}
