import React, { useState } from 'react';
import { View, TextInput, type TextInputProps } from 'react-native';
import { useTheme } from '../../theme/useTheme';
import { Text } from '../Text/Text';
import type { Size, StyleableProps } from '../../types';

export interface InputProps extends StyleableProps, Pick<TextInputProps, 'value' | 'onChangeText' | 'placeholder' | 'secureTextEntry' | 'keyboardType' | 'autoCapitalize' | 'autoFocus' | 'onBlur' | 'onFocus' | 'multiline'> {
  /** Field label rendered above the control. */
  label?: string;
  /** Helper text below the control. Replaced by `error` when present. */
  helperText?: string;
  /** Error message. Sets the error visual state and replaces `helperText`. */
  error?: string;
  /** Control size. Default `"md"`. */
  size?: Size;
  /** Element rendered inside, before the text. */
  leftAdornment?: React.ReactNode;
  /** Element rendered inside, after the text. */
  rightAdornment?: React.ReactNode;
  disabled?: boolean;
}

/**
 * Single-line text field. Anatomy: label · control · helper/error.
 *
 * @remarks
 * State: controlled via `value`/`onChangeText`. Error recolors border, ring,
 * and helper together. Related: {@link TextArea}, {@link SearchBar}.
 * @example
 * <Input label="Email" value={email} onChangeText={setEmail} error={emailError} />
 */
export function Input({
  label, helperText, error, size = 'md', leftAdornment, rightAdornment, disabled,
  value, onChangeText, placeholder, style, testID, onFocus, onBlur, ...rest
}: InputProps) {
  const theme = useTheme();
  const c = theme.colors;
  const dim = theme.sizing[size];
  const [focused, setFocused] = useState(false);
  const hasError = !!error;
  const borderColor = hasError ? c.danger : focused ? c.accent : c.borderStrong;

  return (
    <View style={style}>
      {label && <Text variant="label" weight="medium" tone={hasError ? 'danger' : 'default'} style={{ marginBottom: theme.space[2] }}>{label}</Text>}
      <View
        style={{
          minHeight: dim.height,
          flexDirection: 'row',
          alignItems: 'center',
          gap: theme.space[2],
          paddingHorizontal: theme.space[3] + 2,
          borderRadius: dim.radius,
          borderWidth: 1,
          borderColor,
          backgroundColor: disabled ? c.sunken : c.elevated,
        }}
      >
        {leftAdornment}
        <TextInput
          value={value}
          onChangeText={onChangeText}
          placeholder={placeholder}
          placeholderTextColor={c.textSubtle}
          editable={!disabled}
          onFocus={(e) => { setFocused(true); onFocus?.(e); }}
          onBlur={(e) => { setFocused(false); onBlur?.(e); }}
          testID={testID}
          style={{ flex: 1, color: disabled ? c.textSubtle : c.text, fontSize: dim.fontSize, fontFamily: theme.fontFamily.body, paddingVertical: theme.space[2] }}
          {...rest}
        />
        {rightAdornment}
      </View>
      {(error || helperText) && (
        <Text variant="caption" tone={hasError ? 'danger' : 'subtle'} style={{ marginTop: theme.space[1] + 2 }}>
          {error || helperText}
        </Text>
      )}
    </View>
  );
}
