import React from 'react';
import Svg, { Path, Circle } from 'react-native-svg';

/**
 * Clay icon style: 24×24 grid, 1.7 stroke, round caps/joins, `currentColor`.
 * Every icon takes `size` (default 22) and `color` (default `currentColor`),
 * so it inherits text color and aligns with the type scale.
 *
 * These are a starter set — add more following the same signature.
 */
export interface IconProps {
  /** Square dimension in px. Default 22. */
  size?: number;
  /** Stroke color. Default `currentColor` (inherits from text). */
  color?: string;
}

const base = (size = 22) => ({ width: size, height: size, viewBox: '0 0 24 24', fill: 'none' as const });
const stroke = (color = 'currentColor') => ({ stroke: color, strokeWidth: 1.7, strokeLinecap: 'round' as const, strokeLinejoin: 'round' as const });

export const SearchIcon = ({ size, color }: IconProps) => (
  <Svg {...base(size)}><Circle cx={11} cy={11} r={6.5} {...stroke(color)} /><Path d="m20 20-3.6-3.6" {...stroke(color)} /></Svg>
);
export const PlusIcon = ({ size, color }: IconProps) => (
  <Svg {...base(size)}><Path d="M12 5v14M5 12h14" {...stroke(color)} /></Svg>
);
export const CheckIcon = ({ size, color }: IconProps) => (
  <Svg {...base(size)}><Path d="m5 12.5 4.5 4.5L19 7" {...stroke(color)} strokeWidth={2} /></Svg>
);
export const ChevronRightIcon = ({ size, color }: IconProps) => (
  <Svg {...base(size)}><Path d="m9 6 6 6-6 6" {...stroke(color)} /></Svg>
);
export const CloseIcon = ({ size, color }: IconProps) => (
  <Svg {...base(size)}><Path d="m6 6 12 12M18 6 6 18" {...stroke(color)} strokeWidth={1.8} /></Svg>
);
export const BellIcon = ({ size, color }: IconProps) => (
  <Svg {...base(size)}><Path d="M18 8.5a6 6 0 1 0-12 0c0 5-2 6.5-2 6.5h16s-2-1.5-2-6.5" {...stroke(color)} /><Path d="M10.5 19a1.8 1.8 0 0 0 3 0" {...stroke(color)} /></Svg>
);
