import React from 'react';
import { View, Pressable, type ViewProps, type GestureResponderEvent } from 'react-native';
import { useTheme } from '../../theme/useTheme';
import type { StyleableProps } from '../../types';

export type CardVariant = 'outlined' | 'elevated' | 'filled';

export interface CardProps extends StyleableProps, Pick<ViewProps, 'children'> {
  /** Surface treatment. Default `"outlined"`. */
  variant?: CardVariant;
  /** Inner padding, using a space token key. Default `4` (16px). */
  padding?: keyof ReturnType<typeof useTheme>['space'];
  /** Makes the whole card pressable with a subtle feedback state. */
  onPress?: (e: GestureResponderEvent) => void;
}

/**
 * The primary container surface. Maps its variant straight to elevation tokens.
 *
 * @remarks
 * Do: nest {@link Heading}/{@link Text} for content. Don't: stack elevated cards
 * on elevated cards — flatten to `outlined` inside. Related: {@link Card}, {@link List}.
 * @example
 * <Card variant="elevated" padding={5}>
 *   <Heading level={4}>Weekly digest</Heading>
 *   <Text tone="muted">Everything that changed.</Text>
 * </Card>
 */
export function Card({ variant = 'outlined', padding = 4, onPress, style, children, testID }: CardProps) {
  const theme = useTheme();
  const c = theme.colors;

  const surface = {
    outlined: { backgroundColor: c.surface, borderWidth: 1, borderColor: c.border, shadow: undefined },
    elevated: { backgroundColor: c.elevated, borderWidth: 0, borderColor: 'transparent', shadow: theme.shadow.sm },
    filled: { backgroundColor: c.sunken, borderWidth: 1, borderColor: c.border, shadow: undefined },
  }[variant];

  const boxStyle = [
    {
      borderRadius: theme.radius.lg,
      padding: theme.space[padding],
      backgroundColor: surface.backgroundColor,
      borderWidth: surface.borderWidth,
      borderColor: surface.borderColor,
    },
    surface.shadow,
    style,
  ];

  if (onPress) {
    return (
      <Pressable onPress={onPress} testID={testID} accessibilityRole="button" style={({ pressed }) => [...boxStyle, { opacity: pressed ? 0.94 : 1 }]}>
        {children}
      </Pressable>
    );
  }
  return <View testID={testID} style={boxStyle}>{children}</View>;
}
