import React from 'react';
import { Pressable, View, type GestureResponderEvent } from 'react-native';
import { useTheme } from '../../theme/useTheme';
import type { Variant, Size, A11yProps, StyleableProps } from '../../types';

export interface IconButtonProps extends A11yProps, StyleableProps {
  /** The icon element. Rendered centered; sized to the control's icon token. */
  icon: React.ReactNode;
  /** Visual emphasis. Default `"ghost"`. */
  variant?: Variant;
  /** Control size. Default `"md"`. */
  size?: Size;
  /** Fully rounded (pill/circle) instead of the size radius. Default `false`. */
  round?: boolean;
  /** Disable the button. */
  disabled?: boolean;
  onPress?: (e: GestureResponderEvent) => void;
}

/**
 * A square, icon-only button. Same variants/sizes as {@link Button}.
 *
 * @remarks
 * Accessibility: `accessibilityLabel` is REQUIRED — there is no visible text.
 * Do: use for toolbar and inline actions. Don't: use for primary CTAs (use Button).
 *
 * @example
 * <IconButton icon={<CloseIcon />} accessibilityLabel="Close" onPress={close} />
 */
export function IconButton({
  icon,
  variant = 'ghost',
  size = 'md',
  round = false,
  disabled = false,
  onPress,
  style,
  accessibilityLabel,
  accessibilityHint,
  testID,
}: IconButtonProps) {
  const theme = useTheme();
  const dim = theme.sizing[size];
  const c = theme.colors;

  const bg =
    variant === 'primary' ? c.accent :
    variant === 'danger' ? c.danger :
    variant === 'soft' ? c.accentSoft :
    variant === 'secondary' ? c.elevated : 'transparent';
  const border = variant === 'secondary' ? c.borderStrong : 'transparent';

  return (
    <Pressable
      onPress={onPress}
      disabled={disabled}
      accessibilityRole="button"
      accessibilityLabel={accessibilityLabel}
      accessibilityHint={accessibilityHint}
      accessibilityState={{ disabled }}
      testID={testID}
      style={({ pressed }) => [
        {
          width: dim.height,
          height: dim.height,
          borderRadius: round ? theme.radius.full : dim.radius,
          backgroundColor: bg,
          borderWidth: variant === 'secondary' ? 1 : 0,
          borderColor: border,
          alignItems: 'center',
          justifyContent: 'center',
          opacity: disabled ? 0.5 : pressed ? 0.85 : 1,
        },
        style,
      ]}
    >
      <View>{icon}</View>
    </Pressable>
  );
}
