import React from 'react';
import { Pressable, Text, View, ActivityIndicator, type PressableProps, type GestureResponderEvent } from 'react-native';
import Animated, { useAnimatedStyle, useSharedValue, withTiming } from 'react-native-reanimated';
import { useTheme } from '../../theme/useTheme';
import type { Variant, Size, A11yProps, StyleableProps } from '../../types';

const AView = Animated.createAnimatedComponent(View);

export interface ButtonProps extends A11yProps, StyleableProps {
  /** Button label. Ignored if `children` is provided. */
  children?: React.ReactNode;
  /**
   * Visual emphasis. Default `"primary"`.
   * - `primary` — solid accent, main call to action
   * - `secondary` — outlined, neutral surface
   * - `soft` — tinted accent background, low emphasis
   * - `ghost` — text only, minimal
   * - `danger` — destructive solid
   */
  variant?: Variant;
  /** Control height & padding. Default `"md"`. */
  size?: Size;
  /** Show a spinner and block presses. Default `false`. */
  loading?: boolean;
  /** Disable the button. Default `false`. */
  disabled?: boolean;
  /** Stretch to fill the parent's width. Default `false`. */
  fullWidth?: boolean;
  /** Element rendered before the label (usually an icon). */
  leftIcon?: React.ReactNode;
  /** Element rendered after the label. */
  rightIcon?: React.ReactNode;
  /** Press handler. */
  onPress?: (e: GestureResponderEvent) => void;
}

/**
 * The primary action component.
 *
 * @remarks
 * Do: use exactly one `primary` button per view for the main action.
 * Don't: use `danger` for anything reversible — pair it with a confirm Dialog.
 * Accessibility: `role="button"` is set automatically; provide
 * `accessibilityLabel` when the label is an icon only (prefer `IconButton`).
 * Related: {@link IconButton}, {@link Card}.
 *
 * @example Basic
 * <Button onPress={save}>Save changes</Button>
 *
 * @example With icon + loading
 * <Button variant="soft" leftIcon={<PlusIcon />} loading={saving}>New</Button>
 */
export function Button({
  children,
  variant = 'primary',
  size = 'md',
  loading = false,
  disabled = false,
  fullWidth = false,
  leftIcon,
  rightIcon,
  onPress,
  style,
  accessibilityLabel,
  accessibilityHint,
  testID,
}: ButtonProps) {
  const theme = useTheme();
  const dim = theme.sizing[size];
  const pressed = useSharedValue(0);
  const isDisabled = disabled || loading;

  const palette = getVariant(variant, theme, isDisabled);

  const animatedStyle = useAnimatedStyle(() => ({
    opacity: withTiming(pressed.value ? 0.9 : 1, { duration: theme.motion.duration.fast }),
    transform: [{ scale: withTiming(pressed.value ? 0.98 : 1, { duration: theme.motion.duration.fast }) }],
  }), [theme]);

  return (
    <Pressable
      onPress={onPress}
      onPressIn={() => (pressed.value = 1)}
      onPressOut={() => (pressed.value = 0)}
      disabled={isDisabled}
      accessibilityRole="button"
      accessibilityState={{ disabled: isDisabled, busy: loading }}
      accessibilityLabel={accessibilityLabel}
      accessibilityHint={accessibilityHint}
      testID={testID}
      style={fullWidth ? { alignSelf: 'stretch' } : undefined}
    >
      <AView
        style={[
          {
            height: dim.height,
            paddingHorizontal: dim.paddingX,
            borderRadius: dim.radius,
            backgroundColor: palette.bg,
            borderWidth: palette.borderWidth,
            borderColor: palette.border,
            flexDirection: 'row',
            alignItems: 'center',
            justifyContent: 'center',
            gap: theme.space[2],
            opacity: isDisabled ? 0.55 : 1,
          },
          animatedStyle,
          style,
        ]}
      >
        {loading ? (
          <ActivityIndicator size="small" color={palette.fg} />
        ) : (
          <>
            {leftIcon}
            {children != null && (
              <Text style={{ color: palette.fg, fontSize: dim.fontSize, fontFamily: theme.fontFamily.body, fontWeight: theme.fontWeight.semibold }}>
                {children}
              </Text>
            )}
            {rightIcon}
          </>
        )}
      </AView>
    </Pressable>
  );
}

function getVariant(variant: Variant, theme: ReturnType<typeof useTheme>, _disabled: boolean) {
  const c = theme.colors;
  switch (variant) {
    case 'secondary':
      return { bg: c.elevated, fg: c.text, border: c.borderStrong, borderWidth: 1 };
    case 'soft':
      return { bg: c.accentSoft, fg: c.accent, border: 'transparent', borderWidth: 0 };
    case 'ghost':
      return { bg: 'transparent', fg: c.text, border: 'transparent', borderWidth: 0 };
    case 'danger':
      return { bg: c.danger, fg: '#fff', border: 'transparent', borderWidth: 0 };
    case 'primary':
    default:
      return { bg: c.accent, fg: c.onAccent, border: 'transparent', borderWidth: 0 };
  }
}
