import React, { createContext, useContext, useMemo, useState, useCallback } from 'react';
import { useColorScheme } from 'react-native';
import { lightTheme, darkTheme, type Theme } from './themes';

export type ColorSchemeName = 'light' | 'dark';
export type ColorSchemePref = ColorSchemeName | 'system';

export interface ThemeContextValue {
  /** The resolved theme object. All components read from this. */
  theme: Theme;
  /** Current resolved scheme (never `system`). */
  scheme: ColorSchemeName;
  /** The user's preference, which may be `system`. */
  preference: ColorSchemePref;
  /** Set the preference explicitly. */
  setPreference: (pref: ColorSchemePref) => void;
  /** Convenience toggle between light and dark. */
  toggle: () => void;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export interface ThemeProviderProps {
  children: React.ReactNode;
  /** Override the light theme (e.g. a custom brand). Defaults to Clay's light theme. */
  light?: Theme;
  /** Override the dark theme. Defaults to Clay's dark theme. */
  dark?: Theme;
  /** Initial color-scheme preference. `system` follows the OS. Default: `system`. */
  defaultPreference?: ColorSchemePref;
}

/**
 * Provides the active theme to every Clay component. Wrap your app root once.
 *
 * @example
 * <ThemeProvider defaultPreference="system">
 *   <App />
 * </ThemeProvider>
 */
export function ThemeProvider({
  children,
  light = lightTheme,
  dark = darkTheme,
  defaultPreference = 'system',
}: ThemeProviderProps) {
  const system = useColorScheme();
  const [preference, setPreference] = useState<ColorSchemePref>(defaultPreference);

  const scheme: ColorSchemeName =
    preference === 'system' ? (system === 'dark' ? 'dark' : 'light') : preference;

  const toggle = useCallback(
    () => setPreference((p) => {
      const current = p === 'system' ? (system === 'dark' ? 'dark' : 'light') : p;
      return current === 'dark' ? 'light' : 'dark';
    }),
    [system],
  );

  const value = useMemo<ThemeContextValue>(
    () => ({ theme: scheme === 'dark' ? dark : light, scheme, preference, setPreference, toggle }),
    [scheme, preference, light, dark, toggle],
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

/** Internal accessor. Throws if used outside a ThemeProvider. */
export function useThemeContext(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('Clay: components must be rendered inside <ThemeProvider>.');
  return ctx;
}
