import { palette, space, radius, fontSize, lineHeight, fontWeight, fontFamily, motion, sizing } from './tokens';

/**
 * Semantic color tokens — the names components actually use.
 * Each theme maps meaning onto palette primitives, so switching themes (or
 * providing a custom one) never touches component code.
 */
export interface ColorTokens {
  /** App canvas background. */
  bg: string;
  /** Card / sheet surface, one step above the canvas. */
  surface: string;
  /** Popovers, menus, modals — the highest surface. */
  elevated: string;
  /** Inset wells: inputs, tracks, code blocks. */
  sunken: string;
  /** Hairline borders. */
  border: string;
  /** Stronger borders and disabled fills. */
  borderStrong: string;
  /** Primary text. */
  text: string;
  /** Secondary text. */
  textMuted: string;
  /** Tertiary text, placeholders, captions. */
  textSubtle: string;
  /** Brand accent (clay). */
  accent: string;
  /** Accent pressed / hover. */
  accentHover: string;
  /** Tinted accent background for soft buttons, chips, selection. */
  accentSoft: string;
  /** Foreground on top of `accent`. */
  onAccent: string;
  success: string;
  successSoft: string;
  warning: string;
  warningSoft: string;
  danger: string;
  dangerSoft: string;
  info: string;
  infoSoft: string;
}

export interface ShadowToken {
  shadowColor: string;
  shadowOffset: { width: number; height: number };
  shadowOpacity: number;
  shadowRadius: number;
  /** Android */
  elevation: number;
}

export interface Theme {
  name: 'light' | 'dark' | (string & {});
  colors: ColorTokens;
  space: typeof space;
  radius: typeof radius;
  fontSize: typeof fontSize;
  lineHeight: typeof lineHeight;
  fontWeight: typeof fontWeight;
  fontFamily: typeof fontFamily;
  motion: typeof motion;
  sizing: typeof sizing;
  shadow: { sm: ShadowToken; md: ShadowToken; lg: ShadowToken };
}

