export type DeepPartial<T> = { [K in keyof T]?: T[K] extends object ? DeepPartial<T[K]> : T[K] };

/**
 * Merge a partial override onto a base theme to build a custom brand theme.
 * Only the tokens you specify change; everything else inherits.
 *
 * @example
 * const brand = createTheme(lightTheme, { colors: { accent: '#2A6FDB' } });
 */
export function createTheme(base: Theme, overrides: DeepPartial<Theme> = {}): Theme {
  return deepMerge(base, overrides) as Theme;
}

function deepMerge<T>(base: T, override: DeepPartial<T>): T {
  const out: any = Array.isArray(base) ? [...(base as any)] : { ...base };
  for (const key in override) {
    const v = override[key];
    if (v && typeof v === 'object' && !Array.isArray(v)) out[key] = deepMerge((base as any)[key], v as any);
    else if (v !== undefined) out[key] = v;
  }
  return out;
}
