import React from 'react';
import { Pressable } from 'react-native';
import Animated, { useAnimatedStyle, withTiming, interpolateColor, useDerivedValue } from 'react-native-reanimated';
import { useTheme } from '../../theme/useTheme';
import { useControllableState } from '../../hooks/useControllableState';
import type { A11yProps } from '../../types';

export interface SwitchProps extends A11yProps {
  /** Controlled on/off value. */
  value?: boolean;
  /** Uncontrolled initial value. Default `false`. */
  defaultValue?: boolean;
  /** Called with the next value on toggle. */
  onValueChange?: (value: boolean) => void;
  disabled?: boolean;
  testID?: string;
}

/**
 * A binary on/off toggle with a spring-free, calm slide (Reanimated).
 *
 * @remarks
 * State: controlled (`value` + `onValueChange`) or uncontrolled (`defaultValue`).
 * Tap target stays ≥44px even though the track is smaller.
 * Related: {@link Checkbox}, {@link Radio}.
 * @example
 * <Switch value={wifi} onValueChange={setWifi} accessibilityLabel="Wi-Fi" />
 */
export function Switch({ value, defaultValue = false, onValueChange, disabled, accessibilityLabel, testID }: SwitchProps) {
  const theme = useTheme();
  const [on, setOn] = useControllableState({ value, defaultValue, onChange: onValueChange });
  const progress = useDerivedValue(() => withTiming(on ? 1 : 0, { duration: theme.motion.duration.fast }), [on]);

  const trackStyle = useAnimatedStyle(() => ({
    backgroundColor: interpolateColor(progress.value, [0, 1], [theme.colors.borderStrong, theme.colors.accent]),
  }), [theme]);
  const thumbStyle = useAnimatedStyle(() => ({ transform: [{ translateX: 18 * progress.value }] }), []);

  return (
    <Pressable
      onPress={() => setOn(!on)}
      disabled={disabled}
      accessibilityRole="switch"
      accessibilityState={{ checked: on, disabled }}
      accessibilityLabel={accessibilityLabel}
      testID={testID}
      hitSlop={10}
      style={{ opacity: disabled ? 0.5 : 1 }}
    >
      <Animated.View style={[{ width: 44, height: 26, borderRadius: theme.radius.full, padding: 3, justifyContent: 'center' }, trackStyle]}>
        <Animated.View style={[{ width: 20, height: 20, borderRadius: theme.radius.full, backgroundColor: '#fff' }, theme.shadow.sm, thumbStyle]} />
      </Animated.View>
    </Pressable>
  );
}
