import React from 'react';
import { View } from 'react-native';
import { useTheme } from '../../theme/useTheme';
import { Text } from '../Text/Text';
import type { Status, StyleableProps } from '../../types';

export interface BadgeProps extends StyleableProps {
  children: React.ReactNode;
  /** Semantic status → color. Default `"neutral"`. */
  status?: Status;
  /** Show a leading dot. Default `false`. */
  dot?: boolean;
}

/**
 * A small, static status marker. Uses the shared {@link Status} color set.
 *
 * @remarks
 * Do: use for state (Active, Pending, Beta). Use {@link Chip} for interactive filters.
 * @example
 * <Badge status="success" dot>Active</Badge>
 */
export function Badge({ children, status = 'neutral', dot = false, style, testID }: BadgeProps) {
  const theme = useTheme();
  const c = theme.colors;
  const map: Record<Status, { bg: string; fg: string }> = {
    info: { bg: c.infoSoft, fg: c.info },
    success: { bg: c.successSoft, fg: c.success },
    warning: { bg: c.warningSoft, fg: c.warning },
    danger: { bg: c.dangerSoft, fg: c.danger },
    neutral: { bg: c.sunken, fg: c.textMuted },
  };
  const tone = map[status];

  return (
    <View testID={testID} style={[{ flexDirection: 'row', alignItems: 'center', gap: theme.space[1] + 2, height: 24, paddingHorizontal: theme.space[2] + 2, borderRadius: theme.radius.full, backgroundColor: tone.bg }, style]}>
      {dot && <View style={{ width: 6, height: 6, borderRadius: 3, backgroundColor: tone.fg }} />}
      <Text variant="caption" weight="semibold" style={{ color: tone.fg }}>{children}</Text>
    </View>
  );
}
